INSERT INTO `test_history` VALUES (1,1,1,3,96.50,959,319.70,109,4,0,0,0,1,886,0,4,3,180,890,889,'suç toplumda oluşan düzenini devamını sağlamak ve temel haklar ile özgürlüklerin korunabilmesi için gereken hukuki derğerlin ihlal edilmesi şeklinde haksızlık oluşturan insan davranışlarıdır bu davranışlar ceza hukuku yaptırımlarına tabi tutulan ve kanunun karşılığında ceza yaptırımı öngördüğü fiillerdr suç teşkil eden fiil bir hakkı ihlal ettiği için haksızlık teşkil eder dolayısıyla her suç aynı zamanda haksızlık teşkil etmektedir ancak her haksızlık suç değildir suç içeriği bakımından kanun koyucunun inancına göre devletin amaçlarıyla çatıştığından yaptırım olarak ceza veya güvenlik tedbirlerini gerektiren fiil kapsamındadır bir fiilin suç olup olmadığını belirlemek kanun koyucuya aittir suçla ilgili temel kavramlar şunlardır fail cezai nitelikteki hukuka aykırı fiili iişleyen kişidir yaralama hırsızlık ve dolandırıcılık suçlarında olduğu gibi suçların çoğunluğu herhangi bi','2026-06-21 12:40:49'),(2,1,1,3,97.40,979,326.30,114,3,0,0,0,0,911,4,4,2,180,919,917,'suç toplumda oluşan düzenini devamını sağlamak ve temel haklar ile özgürlüklerin korunabilmesi için gereken hukuki değerlerin ihlal edilmesi şeklinde haksızlık oluşturan insan davranışlarıdır bu davranışlar ceza hukuku yaptırımlarına tabi tutulan ve kanunun karşılığında ceza yaptırımı öngördüğü fiillerdir suç teşkil eden fiil bir hakkı ihlal ettiği için haksızlık teşkil eder dolayısıyla her suç aynı zamanda haksızlık teşkil etmektedir ancak her haksızlık suç değildir suç içeriği bakımından kanun koyucunun inancına göre devletin amaçlarıyla çatıştığından yaptırım olarak ceza veya güvenlik tedbirlerini gerektiren fiil kapsamındadır bir fiilin suç olup olmadığını belirlemek kanun koyucuya aittir suçla ilgili temel kavramlar şunlardır fail cezai nitelikteki hukuka aykırı fiili iişleyen kişidir yaralama hırsızlık ve dolandırıcılık suçlarında olduğu gibi suçların çoğunluğu herhangi bir kimse tarafından işllnne','2026-06-21 13:15:36'),(3,1,30,1,100.00,321,321.00,36,0,1,0,0,0,270,0,6,0,60,276,270,'hak kavramı hukukla ilgili kavramlardan biridir adalet ve hukuka uygunluk anlamlarına gelen hak kelimesi arapça hukuk kelimesinin tekil halidir verilmiş bir emekten dolayı maddi ve manevi yetkidir hak yasalar ve anlaşmaların insana tanıdığı yetkilerin toplamıdır kişiler ','2026-06-21 13:26:04'),(4,1,30,3,93.90,950,316.70,108,7,0,0,0,0,877,17,2,3,180,896,897,'hak kavramı hukukla ilgili temel kavramlardan biridir adalet ve hukuka uygunluk anlamlarına gelen hak kelimesi arapça hukuk kelimesinin tekil halidir verilmiş bir emekten dolayı maddi ve manevi yetkidir hak yasalar ve anlaşmaların insansa tanıdığı yetkilerin toplamıdır kişiler haklarını kullanıp kullanmama iradesine sahiptiler bir hakkın kullanımı ise medeni kanunda belirtildiği üzere dürüstlük ilkesi dahilinde olmalıdır hak sahipleri özel veya tüzel kişiler olabilir sağ olarak doğmak koşuluyla ana rahmine ilk düştüğü andan itiabreb nsanlar hak ehliyetini kazanırlar haklar kanunlarla düzenlenerek koruma altına alınırlar haklar aslında hukuk kurallarına dayanır toplum içinde yaşayan herkesin üstlenmesi gereken belli başlı rolleri bulunur aynı zamanda devletler ve uluslararası kuruluşlar tarafından gücenve altına alınan haklar da bulunmaktadır din ve vicdan ghürriyetii düşünce özgürlüğü ','2026-06-21 13:29:40'),(6,1,5,3,94.50,1040,346.70,120,7,1,0,0,0,975,2,10,5,180,987,982,'kişi işlemeyi kastettiği bir suyçu elverişli hareketlerle doğrudan doğruya icrasına başlayıp elinde olmayan nedenlerle tamamlamazsa teşebbüsten dolayı sorumlu olur suç genelde fiilin işlenmesi ve neticenin meydana gelmesi ile sonuçlanır suçun tam olarak gerçekleşmediği durumlarda da suç genel tanımının dışında kalır işlenen suç tamamlanmaz veya suç unsırlarının eksik olması nedeniyle suçun hukuk tanımına uymamasu durumunda suçun özel görünüş şekillerinden bahsetmek gerekir teşebbüs suçun özel görünüş şekillerinden biridir suç yolunda ilerleyen fail çeşitli aşamalardan geçer suç yolunda icra ve tamamlama olmak üzere iki aşama vardır kasıtlı işlenen suçlarda bahsedilen aşamalara düşünce aşaması da eklenir bu aşama icra aşamasından önce gelir baze nde tamamlanma aşamasını son bulma aşaması takip eder böylece suç yolunda dört aşama vardır denilebilir düşünce aşaması ceza hukukunu ilgilendirmez eyleme dönüşmeyen hiçbir düşüşnce cezalandırılamaz icra aşamasına ge,çilmnesiyl','2026-06-21 17:37:17'),(7,1,4,3,96.50,961,320.30,110,4,1,0,0,1,891,0,16,2,180,907,893,'taksir yasalrda öngörülen dikkat ve özen yükümlülüğü ihlalinden kaynaklanan öngörülebilir ir suçun kasıtsız olarak işlenmesidir taksir ile işlenen fiiller sadece kanunda açıkça belirtilen hallerde başvurulan sorumluluk şeklidir taksirde kusur ağırlığı suçlara göre daha azdır fail çoğu zaman kendisi de bir mağduriyet yaşar özellikle trafik kazalarında bu durum sıklıkla yaşanır dikkatli ve tedbirli davranarak ortaya konulması gereken irade yerine dikkatsiz ve tedbirsiz davranarak başka bir irade ortaya konulur taksirli sorumluluktan söz edebilmek için mutlaka zararlı neticenin gerçekleşmesi gerekir taksirle işlenen suç neticesinde verilecek olan ceza failin kusur oranına göre değişir basit taksir öngörülebilir neticeyi failin öngörememesi sonucunda ortaya çıkar failin dikkatli ve özenli olması gerekirken bu yükümlülüğe ayukırı hareketle suç fiilini işlemediir basit taksir için bilin','2026-06-21 18:35:13'),(8,1,30,3,93.30,989,329.70,112,8,0,0,0,1,937,2,4,4,180,943,943,'hak kavramı hukukla ilgili temel kavramlardan biridir adalet ve hukuka uygunluk anlamlarına gelen hak kelimesi arapça hukuk kelimesinin tekil halidir verilmiş bir emekten dolayı maddi ve manevi yetkidir hak yasalar ve anlaşmaların insana tanıdığı yetkilerin toplamıdır kişiler haklarını kullanıp kullanmama iradesine sahiptiler bir hakkın kullanımı ise medeni kanuında belirtildiği üzere dürstülük ilkesi dahilinde olmalıdır hak sahipleri özel veya tüzel kişiler olabilir sağ olarak doğmak koşuluyla ana arahmine ilk dü