INSERT INTO `texts` VALUES (1,1,'Metin 1','suç toplumda oluşan düzenin devamını sağlamak ve temel haklar ile özgürlüklerin korunabilmesi için gereken hukuki değerlerin ihlal edilmesi şeklinde haksızlık oluşturan insan davranışlarıdır bu davranışlar ceza hukuku yaptırımlarına tabi tutulan ve kanunun karşılığında ceza yaptırımı öngördüğü fiillerdir suç teşkil eden fiil bir hakkı ihlal ettiği için haksızlık teşkil eder dolayısıyla her suç aynı zamanda haksızlık teşkil etmektedir ancak her haksızlık suç değildir suç içeriği bakımından kanun koyucunun inancına göre devletin amaçlarıyla çatıştığından yaptırım olarak ceza veya güvenlik tedbirlerini gerektiren fiil kapsamındadır bir fiilin suç olup olmadığını belirlemek kanun koyucuya aittir suçla ilgili temel kavramlar şunlardır fail cezai nitelikteki hukuka aykırı fiili işleyen kişidir yaralama hırsızlık ve dolandırıcılık suçlarında olduğu gibi suçların çoğunluğu herhangi bir kimse tarafından işlenebilir bunlara genel suçlar denir bazı suçlarsa sadece belli hukuki veya fiili durumdaki kişiler tarafından işlenebilir bunlara ise mahsus suçlar denir her suçun faili olduğu gibi mutlaka hukuki konusu bulunmaktadır örneğin hırsızlık suçunun hukuki konusu zilyetlik yaralama suçunun hukuki konusu vücut bütünlüğü insan öldürme suçunun hukuki konusu yaşam hakkının ihlalleridir suçun maddi konularına bakacak olursak yalnızca maddi varlığı bulunan varlıklar üzerinde suç işlenebilir insan suçun maddi konusu olabilir tüzel kişiler topluluklar ve cismani varlığı olmayan şeyler suçun maddi konusunu oluşturamazlar örneğin hırsızlık suçunun maddi konusunu çalınan eşya oluştururken kasten öldürme suçunun maddi konusunu insan oluşturmaktadır mağdur insan toplum devlet ve tüzel kişiler olabilmektedir her suçun mutlaka mağduru vardır suçun mağdurları suç işlenirken hayatta olan kişilerdir kimse kendi kendisine karşı suç işleyemez örneğin intihar suç değildir ancak şikayete bağlı suçlarda şikayet hakkı kullanımı suçun mağduruna tanınmıştır suç 